def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            score = abs(ratio) * 100
        elif ratio == 1:
            factor = 7
            for n in range(1, 10):
                score += (factor ** n) / (n * 3) * np.sin(ratio * n * np.pi)
            priorities[i] = score + 50
            continue
        elif ratio > 1:
            penalty = 0
            for p in range(1, 7):
                penalty += (ratio ** (2 * p)) / (p + 1) * np.log1p(p)
            adjustment = 0
            for q in range(1, 4):
                adjustment += (-1)**q * np.sqrt(ratio + q) / (q * 2)
            priorities[i] = (ratio ** 4) + penalty + adjustment
        else:
            for j in range(1, 8):
                sign = (-1) ** (j + 1)
                factor = np.exp(-ratio * j)
                term = sign * (ratio ** j) * factor / (j * 0.7)
                score += term
            multiplier = 20 if ratio < 0.2 else 12 if ratio < 0.5 else 8 if ratio < 0.75 else 4
            extra = 0
            if ratio > 0.6:
                for m in range(1, 5):
                    extra += np.tanh(ratio * m) / (m + 0.5)
            priorities[i] = abs(score) * multiplier + extra
        if np.isnan(priorities[i]) or np.isinf(priorities[i]):
            priorities[i] = np.inf
    return priorities
